function convertirAHorasMinutos(horaStr) {
  // Convierte "HH:MM" a minutos totales (ej: "11:30" → 690 minutos)
  const [hh, mm] = horaStr.split(':').map(Number);
  return hh * 60 + mm;
}

for (const item of $input.all()) {
  const horaInput = item.json.hora || item.json.hora; // Compatible con "hora" o "hora"
  const minutosInput = convertirAHorasMinutos(horaInput);

  // ---- CONFIGURACIÓN PARA TU NEGOCIO ----
  const inicioAtencion = convertirAHorasMinutos("11:00"); // 660 minutos
  const finAtencion = convertirAHorasMinutos("14:00");   // 840 minutos
  // --------------------------------------

  let estado = "válido";
  let justificacion = "";

  // Validación principal
  if (minutosInput < inicioAtencion || minutosInput >= finAtencion) {
    estado = "inválido";
    justificacion = "Fuera del horario de atención (11:00 - 14:00)";
  }

  // Guardamos resultados
  item.json.horaEstado = estado;
  item.json.horaJustificacion = justificacion;
}

return $input.all();

const fechaTexto = $input.first().json.Fecha;
const fechaInput = new Date(fechaTexto);
const fechaActual = new Date();

// Formatear ambas fechas a YYYY-MM-DD
const formatoFecha = (fecha) => fecha.toISOString().substring(0, 10);

const fechaInputStr = formatoFecha(fechaInput);
const fechaActualStr = formatoFecha(fechaActual);

if (fechaInputStr < fechaActualStr) {
  return [
    {
      json: {
        valida: false,
        mensaje: "Fecha inválida. Es una fecha pasada.",
        fecha: fechaInputStr
      }
    }
  ];
} else {
  return [
    {
      json: {
        valida: true,
        mensaje: "La fecha es válida (hoy o en el futuro).",
        fecha: fechaInputStr
      }
    }
  ];
}

const raw = $('When Executed by Another Workflow').first().json.Fecha;

// Convertir a objeto Date
const date = new Date(raw);

// Formatear componentes
const dd = String(date.getDate()).padStart(2, '0');
const mm = String(date.getMonth() + 1).padStart(2, '0'); // getMonth() es base 0
const yyyy = date.getFullYear();
const HH = String(date.getHours()).padStart(2, '0');
const min = String(date.getMinutes()).padStart(2, '0');

// Resultado final
const formatted = `${dd}/${mm}/${yyyy} ${HH}:${min}`;

return [{ json: { formato_final: formatted } }];

const input = $input.first().json.formato_final; // "17/04/2025 08:00"

const [fechaRaw, hora] = input.split(" ");
const [dia, mes, año] = fechaRaw.split("/");

const fechaISO = `${año}-${mes}-${dia}T00:00:00Z`;
const fechaDate = new Date(fechaISO);

const diasSemana = ["domingo", "lunes", "martes", "miércoles", "jueves", "viernes", "sábado"];
const diaSemana = diasSemana[fechaDate.getUTCDay()];

return [{
  json: {
    query: input,
    fecha: fechaRaw,
    hora: hora,
    diaSemana: diaSemana
  }
}];

